import React, { useState } from "react";
const { userID, setUserID } = useUserStore();

function NewCardPanel(prop) {
  const [accountInfo, setAccountInfo] = useState({
    name: null,
    bank: null,
    balance:null
  })

  function eventHandler(e) {

    setAccountInfo( (prev) => ({
      ...prev,
      [e.target.name]: e.target.value
    })  )

  }

 async function newAccount(event) {

  event.preventDefault(); // prevent form from refreshing the page

  console.log("New account:", accountInfo);

  const res = await fetch ('http://localhost:5001/api/newAccountInfo', {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ info: accountInfo, ID: userID })
  })

  }





  return (
    <div className="newCardInput">
      <form className="form-width" onSubmit={newAccount}>
        <div className="mb-3">
          <label for="exampleFormControlInput1" className="form-label">
            Account Name:
          </label>
          <input
            type="text"
            className="form-control"
            id="exampleFormControlInput1"
            placeholder="Example: Saving"
            name="name"
            value={accountInfo.name}
            onChange={eventHandler}
          />

          <label for="exampleFormControlInput1" className="form-label">
            Bank Name:
          </label>
          <input
            type="text"
            className="form-control"
            id="exampleFormControlInput1"
            placeholder="Example: TD"
            name="bank"
            value={accountInfo.bank}
            onChange={eventHandler}
          />

          <label for="exampleFormControlInput1" className="form-label">
            Balance:
          </label>
          <input
            type="text"
            className="form-control"
            id="exampleFormControlInput1"
            placeholder="Example: 1000.00"
            name="balance"
            value={accountInfo.balance}
            onChange={eventHandler}
          />
        </div>
        <div class="col-auto">
          <button type="submit" class="btn btn-primary mb-3">
            Add Account
          </button>
        </div>
      </form>
    </div>
  );
}

export default NewCardPanel;
